using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetrics _evaluationMetrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 0);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        (_model, _evaluationMetrics, _categoryLabels) = TrainAndEvaluate(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    private (ITransformer model, EvaluationMetrics metrics, string[] labels) TrainAndEvaluate(
        IDataView dataView)
    {
        // Combine text features and build the pipeline
        var pipeline = _mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(dataView);

        // Evaluate on training data (small dataset — no hold-out split)
        var predictions = model.Transform(dataView);
        var mlMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        // Extract ordered label names from the key-value mapping
        var labelColumn = predictions.Schema["Label"];
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetKeyValues(ref labelBuffer);
        var labels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        var perClass = new List<PerClassMetric>();
        for (var i = 0; i < labels.Length; i++)
        {
            perClass.Add(new PerClassMetric
            {
                Class = labels[i],
                Precision = mlMetrics.PerClassPrecision[i],
                Recall = mlMetrics.PerClassRecall[i],
                F1Score = 2 * mlMetrics.PerClassPrecision[i] * mlMetrics.PerClassRecall[i]
                    / (mlMetrics.PerClassPrecision[i] + mlMetrics.PerClassRecall[i])
            });
        }

        var metrics = new EvaluationMetrics
        {
            MacroAccuracy = mlMetrics.MacroAccuracy,
            MicroAccuracy = mlMetrics.MicroAccuracy,
            LogLoss = mlMetrics.LogLoss,
            LogLossReduction = mlMetrics.LogLossReduction,
            PerClassMetrics = perClass.ToArray()
        };

        return (model, metrics, labels);
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationMetrics GetEvaluationMetrics() => _evaluationMetrics;
}

