using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(TicketClassifierService classifier) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        var prediction = classifier.Predict(request);
        return Ok(prediction);
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        return Ok(classifier.GetEvaluationMetrics());
    }
}

